import { useState, useEffect } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);

  useEffect(() => {
    if (result) {
      let start = 0;
      const end = result.fraud_confidence_score;
      const duration = 1000; // animation duration in ms
      const stepTime = 20;
      const step = (end - start) / (duration / stepTime);
      const interval = setInterval(() => {
        start += step;
        if (start >= end) {
          start = end;
          clearInterval(interval);
        }
        setAnimatedScore(Math.round(start));
      }, stepTime);
    }
  }, [result]);

  const handleFileChange = (e) => {
    setError(null);
    const selected = e.target.files[0];
    setFile(selected);
    setPreview(selected ? URL.createObjectURL(selected) : null);
    setResult(null);
    setAnimatedScore(0);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);
    setError(null);
    setAnimatedScore(0);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });
      if (!response.ok) throw new Error("Server error!");
      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong with the server!");
    }

    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    setZoom(false);
    setAnimatedScore(0);
  };

  const downloadReport = () => {
    if (!result) return;
    const blob = new Blob([JSON.stringify(result, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `audit_report_${new Date().toISOString()}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  // Gauge color gradient green → yellow → red
  const gaugeColor = (score) => {
    if (score <= 50) return "#22c55e"; // green
    if (score <= 80) return "#f59e0b"; // yellow
    return "#ef4444"; // red
  };

  const verdictColor = (verdict) => {
    if (!verdict) return "#555";
    if (verdict.toLowerCase() === "fraud") return "#ef4444";
    if (verdict.toLowerCase() === "suspicious") return "#f59e0b";
    return "#22c55e"; // safe
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <header style={styles.header}>
          <h1 style={styles.logo}>ClaimPilot AI</h1>
          <p style={styles.tagline}>Smart Vehicle Damage Assessment</p>
          <p style={styles.subtagline}>
            Upload a damaged vehicle image, get repair cost estimates, fraud analysis, and a detailed audit report.
          </p>
        </header>

        <div
          style={styles.uploadCard}
          onDragOver={(e) => e.preventDefault()}
          onDrop={(e) => {
            e.preventDefault();
            handleFileChange({ target: { files: [e.dataTransfer.files[0]] } });
          }}
        >
          {preview && (
            <img
              src={preview}
              alt="preview"
              style={zoom ? styles.previewZoom : styles.previewImage}
              onClick={() => setZoom(!zoom)}
            />
          )}
          <label style={styles.uploadLabel}>
            {file ? file.name : "Click or drag to upload image"}
            <input
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={handleFileChange}
            />
          </label>

          <div style={{ display: "flex", justifyContent: "center", gap: "10px" }}>
            <button
              onClick={handleUpload}
              disabled={loading}
              style={loading ? styles.buttonDisabled : styles.button}
            >
              {loading ? "Analyzing..." : "Run AI Audit"}
            </button>
            {file && (
              <button onClick={handleReset} style={styles.resetButton}>
                Reset
              </button>
            )}
          </div>
          {error && <p style={styles.error}>{error}</p>}
        </div>

        {result && (
          <div style={styles.resultCard}>
            <h2 style={styles.resultTitle}>Audit Summary</h2>
            <p style={styles.auditTime}>Audit Date: {new Date().toLocaleString()}</p>

            <div style={styles.stats}>
              <div style={styles.statBox}>
                <p>Total Estimate</p>
                <h3>PKR {result.total_estimate_pkr}</h3>
              </div>

              <div style={styles.statBox}>
                <p>Fraud Score</p>
                <div style={styles.gaugeContainer}>
                  <svg viewBox="0 0 36 36" style={styles.gauge}>
                    <path
                      style={{ stroke: "#eee" }}
                      d="M18 2.0845
                         a 15.9155 15.9155 0 0 1 0 31.831
                         a 15.9155 15.9155 0 0 1 0 -31.831"
                      fill="none"
                      strokeWidth="2.8"
                    />
                    <path
                      style={{ stroke: gaugeColor(animatedScore), transition: "stroke-dasharray 1s ease" }}
                      strokeDasharray={`${animatedScore}, 100`}
                      d="M18 2.0845
                         a 15.9155 15.9155 0 0 1 0 31.831
                         a 15.9155 15.9155 0 0 1 0 -31.831"
                      fill="none"
                      strokeWidth="2.8"
                    />
                    <text x="18" y="20.35" style={styles.gaugeText}>
                      {animatedScore}%
                    </text>
                  </svg>
                </div>
              </div>

              <div style={{ ...styles.statBox, color: verdictColor(result.verdict) }}>
                <p>Verdict</p>
                <h3>{result.verdict}</h3>
              </div>

              <div style={styles.statBox}>
                <p>Damaged Parts</p>
                <h3>{result.damaged_parts?.length || 0}</h3>
              </div>

              {result.estimated_repair_time && (
                <div style={styles.statBox}>
                  <p>Estimated Repair Time</p>
                  <h3>{result.estimated_repair_time}</h3>
                </div>
              )}
            </div>

            <div style={styles.details}>
              <h3>Fraud Analysis</h3>
              <p>{result.fraud_analysis || "No fraud detected."}</p>

              <h3>Damaged Parts</h3>
              {result.damaged_parts?.length ? (
                <ul>
                  {result.damaged_parts.map((part, index) => (
                    <li key={index}>{part}</li>
                  ))}
                </ul>
              ) : (
                <p>No parts detected.</p>
              )}

              <h3>Itemized Costs</h3>
              <pre style={styles.pre}>
                {JSON.stringify(result.itemized_costs, null, 2)}
              </pre>

              <button onClick={downloadReport} style={styles.downloadButton}>
                Download Audit Report
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

